.darma-loader-darma-custom-478 {
   width: 40px;
   aspect-ratio: 1;
   border:2px solid;
   box-sizing: border-box;
   color: var(--loader-color, #16a34a);
   background: radial-gradient(circle 3px, currentColor 95%,#0000), linear-gradient( currentColor 50%,#0000 0) 50%/3px 80% no-repeat, linear-gradient(90deg,currentColor 50%,#0000 0) 50%/60% 3px no-repeat;
   position: relative;
}
.darma-loader-darma-custom-478:before  {
  content: "";
   position: absolute;
   height: 50px;
   inset: 100% 10% auto;
   background: radial-gradient(circle closest-side at 50% calc(100% - 10px), currentColor 94%,#0000), linear-gradient(currentColor 0 0) top/3px 80% no-repeat;
   transform-origin: top;
   animation: darma-loader-darma-custom-478-l2 2s infinite cubic-bezier(0.5,200,0.5,-200);
}
@keyframes darma-loader-darma-custom-478-l2  {
  100% {transform: rotate(0.4deg)}
}

